int N, C, A[6], bc[1 << 5];

int P[333], Q[333], M[1<<5][1<<5], V;

long long prv[333][333];

long long nxt[333][333];



int main()

{

	scanf("%d %d", &N, &C);

	for (int i = 0; i < N; i++) scanf("%d", &A[i]);

	sort(A, A + N);



